	const sections: SectionDef[] = [
		{ id: 'general', title: { ru: 'Общее', en: 'General' }, icon: 'cube', description: { ru: 'Базовые настройки и быстрый доступ к подключениям.', en: 'Core settings and quick access to connections.' } },
		{ id: 'auto_mode', title: { ru: 'Автомодель', en: 'Auto Model' }, icon: 'spark', description: { ru: 'Роутинг по типу задачи и выбор модели по профилю.', en: 'Route tasks by type and pick the best model profile.' } },
		{ id: 'chat_memory', title: { ru: 'Память чата', en: 'Chat Memory' }, icon: 'database', description: { ru: 'Контроль retrieval, summary и бюджетов контекста.', en: 'Control retrieval, summarization, and context budgets.' } },
		{ id: 'multimodal', title: { ru: 'Мультимодал', en: 'Multimodal' }, icon: 'chat', description: { ru: 'Параметры мультимодальных сценариев и STT.', en: 'Multimodal and speech-to-text controls.' } },
