		{ id: 'media_gallery', title: { ru: 'Галерея', en: 'Gallery' }, icon: 'image', description: { ru: 'Каталог изображений с метаданными и связью с чатом.', en: 'Image catalog with metadata and chat links.' } },
		{ id: 'model_court', title: { ru: 'Суд моделей', en: 'Model Court' }, icon: 'scales', description: { ru: 'Параллельные ответы и выбор лучшего результата.', en: 'Parallel answers and best-response judging.' } },
		{ id: 'deep_research', title: { ru: 'Deep Research', en: 'Deep Research' }, icon: 'search', description: { ru: 'Ручной ресерч по веб-источникам с итоговой сводкой и цитированием.', en: 'Manual web research mode with synthesized answer and citations.' } },
