		memory_summary_token_budget: 500,
		memory_max_recent_messages: 24,
		memory_summary_interval: 8,
		memory_summary_window_messages: 20,
		memory_summary_min_messages: 8,

		auto_enable_manual_override: true,
		auto_show_routing_reason: true,
		auto_enable_domain_hint: true,
		auto_enforce_model_profile: true,
		auto_auto_downgrade_on_latency: false,
		auto_show_latency_badge: true,
		auto_allow_provider_mixing: true,
		auto_low_confidence_threshold: 0.74,
		auto_classifier_temperature: 0,
		auto_classifier_max_tokens: 16,
		auto_classifier_timeout_seconds: 12,
		auto_classifier_confidence_threshold: 0.65,
		auto_classifier_system_prompt_template: 'You are a routing classifier. Output only one label.',
		auto_classifier_user_prompt_template:
			'Classify this user request into exactly one label from: CODING, IMAGE_GENERATION, VISION, REASONING, GENERAL.\nUser request:\n{{user_message}}\nReturn only the label.',
		auto_classifier_model: 'mws-gpt-alpha',
		auto_task_model_general: 'mws-gpt-alpha',
		auto_task_model_coding: 'qwen3-coder-480b-a35b',
		auto_task_model_reasoning: 'glm-4.6-357b',
		auto_task_model_vision: 'qwen2.5-vl-72b',
		auto_task_model_image_generation: 'qwen-image-lightning',
		auto_model_type_overrides_json: '{}',
		auto_task_override_prompt_template:
			'Continue the same task in a better way. Use the previous assistant text as context, apologize briefly for the wrong start, and continue.\n\nPrevious assistant text:\n{{last_message}}\n\nUser request:\n{{user_message}}\n\nPrevious task type: {{previous_task_type}}\nNew task type: {{new_task_type}}',
		default_model_avatar_url: '/v1/assets/model-avatars/default',
		multimodal_stt_model: 'whisper-medium',

		autopilot_enable_stream_steps: true,
		autopilot_enable_auto_retry: true,
		autopilot_enable_risk_guard: true,
		autopilot_enable_partial_result_publish: true,
		autopilot_enable_cost_guard: false,
		autopilot_enable_plan_preview: true,
		autopilot_enable_human_handoff: true,

		model_court_enabled: true,
		model_court_candidates_count: 3,
		model_court_candidate_timeout_seconds: 45,
		model_court_judge_model: 'glm-4.6-357b',
		model_court_enable_anonymous_judging: true,

		deep_research_enabled: true,
		deep_research_max_queries: 3,
		deep_research_max_sources: 6,
		deep_research_fetch_timeout_seconds: 12,
		deep_research_source_char_limit: 2500,
		deep_research_max_output_tokens: 1200,
		deep_research_link_capture_mode: 'attach_only',
		media_gallery_enabled: true,
		media_gallery_page_size: 24,
		media_gallery_max_filters: 10,
		media_gallery_retention_days: 365,

		workspace_enable_shared_workspaces: false,
		workspace_enable_file_tree_sync: true,
		workspace_enable_workspace_scoping: true,
		workspace_enable_diff_preview: true,
		workspace_enable_conflict_guards: true,
		workspace_enable_session_locks: true,
		workspace_enable_workspace_templates: true,
		workspace_max_files_per_workspace: 1200
	};

	const i18n = getContext('i18n');
	let currentLang = 'en';
	$: currentLang = (($i18n?.language as string) || 'en').toLowerCase();
	const isRu = () => currentLang.startsWith('ru');
	const tr = (ru: string, en: string) => (isRu() ? ru : en);
	const tl = (value: { ru: string; en: string }) => (isRu() ? value.ru : value.en);
	const tip = (ru: string, en?: string) =>
		`<div style="max-width: 340px; white-space: normal; text-align: left;">${tr(
			ru,
			en ?? `This setting controls the related GPTHub behavior. (${ru})`
		)}</div>`;
	const benchmarkStepText = (progress: number, kind: 'classifier' | 'text') => {
		if (progress < 20) {
			return kind === 'classifier'
				? tr('Подготовка бенчмарка классификатора...', 'Preparing classifier benchmark...')
				: tr('Подготовка текстового бенчмарка...', 'Preparing text benchmark...');
		}
		if (progress < 75) {
			return kind === 'classifier'
				? tr('Запросы к моделям-кандидатам...', 'Running candidate model requests...')
				: tr('Генерация ответов моделей...', 'Generating model answers...');
		}
		if (progress < 100) {
			return kind === 'classifier'
				? tr('Подсчет Accuracy и Macro-F1...', 'Calculating Accuracy and Macro-F1...')
				: tr('Подсчет итоговых score...', 'Calculating final scores...');
		}
		return tr('Завершение...', 'Finalizing...');
	};

	let selectedSection: SectionId = 'general';
	let autoConstantsExpanded = false;
	let sectionSearch = '';

	let featureLoading = true;
	let featureSaving = false;
	let featureSettingsReady = false;
	let autosaveTimer: ReturnType<typeof setTimeout> | null = null;
	let lastSavedFeatureSettingsSnapshot = '';
	let autosaveErrorNotified = false;
	let healthStatus = 'unknown';
	let featureSettings: FeatureSettings = { ...defaultFeatureSettings };
	let availableModels: SelectModelOption[] = [];
	let autoModelFieldLocks: Record<AutoModelLockKey, boolean> = {
		classifier: true,
		task_general: true,
		task_coding: true,
		task_reasoning: true,
		task_vision: true,
		task_image_generation: true
	};
	let modelTypeRows: ModelTypeRow[] = [];
	let lastAppliedOverridesJson = '{}';

	const TASK_TYPES: ModelTaskType[] = ['GENERAL', 'CODING', 'REASONING', 'VISION', 'IMAGE_GENERATION'];

	let defaultAvatarPreviewUrl = '';
	let defaultAvatarFile: File | null = null;
	let defaultAvatarUploading = false;
	let defaultAvatarFilename = '';
	let defaultAvatarInputEl: HTMLInputElement;

	let classifierBenchmarkLoading = false;
	let classifierBenchmarkProgress = 0;
	let classifierProgressTimer: ReturnType<typeof setInterval> | null = null;
	let classifierBenchmarkResult: {
		entries: Array<{ model_id: string; accuracy: number; macro_f1: number; correct: number; total: number }>;
		winner_model_id?: string | null;
	} | null = null;
	let classifierBenchmarkApplying = false;

	let textBenchmarkLoading = false;
	let textBenchmarkProgress = 0;
	let textProgressTimer: ReturnType<typeof setInterval> | null = null;
	let textBenchmarkResult: {
		entries: Array<{ category: string; model_id: string; score: number; answered: number; total: number }>;
	} | null = null;
	let textBenchmarkApplying = false;

	$: selectedSectionDef = sections.find((s) => s.id === selectedSection) ?? sections[0];
	$: filteredSections = sections.filter((section) => {
		const query = sectionSearch.trim().toLowerCase();
		if (!query) return true;
		return (
			tl(section.title).toLowerCase().includes(query) || tl(section.description).toLowerCase().includes(query)
		);
	});

	const refreshGeneral = async () => {
		try {
			const health = await getGPTHubHealth(localStorage.token);
			healthStatus = health?.status ?? 'unknown';
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось загрузить настройки GPTHub', 'Failed to load GPTHub settings'));
		}
	};

	const refreshFeatureSettings = async () => {
		featureLoading = true;
		try {
			const data = await getFeatureSettings(localStorage.token);
			featureSettings = { ...defaultFeatureSettings, ...(data ?? {}) };
			lastSavedFeatureSettingsSnapshot = JSON.stringify(buildFeaturePayload(featureSettings));
			featureSettingsReady = true;
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось загрузить настройки фич GPTHub', 'Failed to load GPTHub feature settings'));
		} finally {
			featureLoading = false;
		}
	};

	const refreshAvailableModels = async () => {
		try {
			const response = await getOpenAIModels(localStorage.token);
			const source = Array.isArray(response?.data)
				? response.data
				: Array.isArray(response)
					? response
					: [];
			const mapped = source
				.map((item: Record<string, unknown>) => {
					const id = String(item?.id ?? '').trim();
					const name = String(item?.name ?? id).trim();
					const avatar = String(item?.profile_image_url ?? item?.avatar_url ?? '').trim();
					const category = String(item?.category ?? '').toLowerCase();
					if (!id) return null;
					let inferredType: ModelTaskType = 'GENERAL';
					if (category.includes('coding')) inferredType = 'CODING';
					else if (category.includes('reason')) inferredType = 'REASONING';
					else if (category.includes('vision')) inferredType = 'VISION';
					else if (category.includes('image')) inferredType = 'IMAGE_GENERATION';
					return { id, label: name, avatar_url: avatar, inferred_type: inferredType };
				})
				.filter(Boolean) as SelectModelOption[];
			const deduped = Array.from(new Map(mapped.map((m) => [m.id, m])).values());
			availableModels = deduped.sort((a, b) => a.label.localeCompare(b.label));
		} catch (error) {
			console.error(error);
			availableModels = [];
		}
	};

	const updateFeatureNumber = (key: keyof FeatureSettings, value: string) => {
		const parsed = Number(value);
		if (!Number.isFinite(parsed)) return;
		featureSettings = { ...featureSettings, [key]: parsed };
	};

	const buildFeaturePayload = (source: FeatureSettings) => ({
		mws_stub_mode: Boolean(source.mws_stub_mode),
		mws_default_model: String(source.mws_default_model || ''),
		langgraph_recursion_limit: Number(source.langgraph_recursion_limit),
		max_qa_iterations: Number(source.max_qa_iterations),
		memory_recall_top_k: Number(source.memory_recall_top_k),
		memory_lexical_candidates: Number(source.memory_lexical_candidates),
		memory_thread_boost: Number(source.memory_thread_boost),
		memory_chat_history_token_budget: Number(source.memory_chat_history_token_budget),
		memory_retrieval_token_budget: Number(source.memory_retrieval_token_budget),
		memory_summary_token_budget: Number(source.memory_summary_token_budget),
		memory_max_recent_messages: Number(source.memory_max_recent_messages),
		memory_summary_interval: Number(source.memory_summary_interval),
		memory_summary_window_messages: Number(source.memory_summary_window_messages),
		memory_summary_min_messages: Number(source.memory_summary_min_messages),
		auto_enable_manual_override: Boolean(source.auto_enable_manual_override),
		auto_show_routing_reason: Boolean(source.auto_show_routing_reason),
		auto_enable_domain_hint: Boolean(source.auto_enable_domain_hint),
		auto_enforce_model_profile: Boolean(source.auto_enforce_model_profile),
		auto_auto_downgrade_on_latency: Boolean(source.auto_auto_downgrade_on_latency),
		auto_show_latency_badge: Boolean(source.auto_show_latency_badge),
		auto_allow_provider_mixing: Boolean(source.auto_allow_provider_mixing),
		auto_low_confidence_threshold: Number(source.auto_low_confidence_threshold),
		auto_classifier_temperature: Number(source.auto_classifier_temperature),
		auto_classifier_max_tokens: Number(source.auto_classifier_max_tokens),
		auto_classifier_timeout_seconds: Number(source.auto_classifier_timeout_seconds),
		auto_classifier_confidence_threshold: Number(source.auto_classifier_confidence_threshold),
		auto_classifier_system_prompt_template: String(source.auto_classifier_system_prompt_template || ''),
		auto_classifier_user_prompt_template: String(source.auto_classifier_user_prompt_template || ''),
		auto_classifier_model: String(source.auto_classifier_model || ''),
		auto_task_model_general: String(source.auto_task_model_general || ''),
		auto_task_model_coding: String(source.auto_task_model_coding || ''),
		auto_task_model_reasoning: String(source.auto_task_model_reasoning || ''),
		auto_task_model_vision: String(source.auto_task_model_vision || ''),
		auto_task_model_image_generation: String(source.auto_task_model_image_generation || ''),
		auto_model_type_overrides_json: String(source.auto_model_type_overrides_json || '{}'),
		auto_task_override_prompt_template: String(source.auto_task_override_prompt_template || ''),
		default_model_avatar_url: String(source.default_model_avatar_url || ''),
		multimodal_stt_model: String(source.multimodal_stt_model || 'whisper-medium'),
		autopilot_enable_stream_steps: Boolean(source.autopilot_enable_stream_steps),
		autopilot_enable_auto_retry: Boolean(source.autopilot_enable_auto_retry),
		autopilot_enable_risk_guard: Boolean(source.autopilot_enable_risk_guard),
		autopilot_enable_partial_result_publish: Boolean(source.autopilot_enable_partial_result_publish),
		autopilot_enable_cost_guard: Boolean(source.autopilot_enable_cost_guard),
		autopilot_enable_plan_preview: Boolean(source.autopilot_enable_plan_preview),
		autopilot_enable_human_handoff: Boolean(source.autopilot_enable_human_handoff),
		model_court_enabled: Boolean(source.model_court_enabled),
		model_court_candidates_count: Number(source.model_court_candidates_count),
		model_court_candidate_timeout_seconds: Number(source.model_court_candidate_timeout_seconds),
		model_court_judge_model: String(source.model_court_judge_model || ''),
		model_court_enable_anonymous_judging: Boolean(source.model_court_enable_anonymous_judging),
		deep_research_enabled: Boolean(source.deep_research_enabled),
		deep_research_max_queries: Number(source.deep_research_max_queries),
		deep_research_max_sources: Number(source.deep_research_max_sources),
		deep_research_fetch_timeout_seconds: Number(source.deep_research_fetch_timeout_seconds),
		deep_research_source_char_limit: Number(source.deep_research_source_char_limit),
		deep_research_max_output_tokens: Number(source.deep_research_max_output_tokens),
		deep_research_link_capture_mode: String(source.deep_research_link_capture_mode || 'attach_only'),
		media_gallery_enabled: Boolean(source.media_gallery_enabled),
		media_gallery_page_size: Number(source.media_gallery_page_size),
		media_gallery_max_filters: Number(source.media_gallery_max_filters),
		media_gallery_retention_days: Number(source.media_gallery_retention_days),
		workspace_enable_shared_workspaces: Boolean(source.workspace_enable_shared_workspaces),
		workspace_enable_file_tree_sync: Boolean(source.workspace_enable_file_tree_sync),
		workspace_enable_workspace_scoping: Boolean(source.workspace_enable_workspace_scoping),
		workspace_enable_diff_preview: Boolean(source.workspace_enable_diff_preview),
		workspace_enable_conflict_guards: Boolean(source.workspace_enable_conflict_guards),
		workspace_enable_session_locks: Boolean(source.workspace_enable_session_locks),
		workspace_enable_workspace_templates: Boolean(source.workspace_enable_workspace_templates),
		workspace_max_files_per_workspace: Number(source.workspace_max_files_per_workspace)
	});

	const persistFeatureSettings = async () => {
		if (!featureSettingsReady || featureLoading || featureSaving) return;
		const payload = buildFeaturePayload(featureSettings);
		const snapshot = JSON.stringify(payload);
		if (snapshot === lastSavedFeatureSettingsSnapshot) return;

		featureSaving = true;
		try {
			const saved = await updateFeatureSettings(localStorage.token, payload);
			featureSettings = { ...defaultFeatureSettings, ...(saved ?? {}) };
			lastSavedFeatureSettingsSnapshot = JSON.stringify(buildFeaturePayload(featureSettings));
			if (featureSettings.multimodal_stt_model) {
				try {
					const audioConfig = await getAudioConfig(localStorage.token);
					const currentWhisperModel = String(audioConfig?.stt?.WHISPER_MODEL || '').trim();
					const selectedWhisperModel = String(featureSettings.multimodal_stt_model || '').trim();
					if (selectedWhisperModel && selectedWhisperModel !== currentWhisperModel) {
						await updateAudioConfig(localStorage.token, {
							tts: audioConfig.tts,
							stt: {
								...audioConfig.stt,
								WHISPER_MODEL: selectedWhisperModel
							}
						});
					}
				} catch (audioError) {
					console.error(audioError);
				}
			}
			autosaveErrorNotified = false;
			dispatch('save');
		} catch (error) {
			console.error(error);
			if (!autosaveErrorNotified) {
				toast.error(tr('Не удалось автоматически сохранить настройки GPTHub', 'Failed to autosave GPTHub settings'));
				autosaveErrorNotified = true;
			}
		} finally {
			featureSaving = false;
		}
	};

	const toggleAutoModelFieldLock = (key: AutoModelLockKey) => {
		if (!autoModelFieldLocks[key]) {
			autoModelFieldLocks = { ...autoModelFieldLocks, [key]: true };
			return;
		}
		const confirmed = window.confirm(
			tr(
				'Разблокировать это поле выбора модели? Это может повлиять на роутинг.',
				'Unlock this model selector field? This may affect routing behavior.'
			)
		);
		if (confirmed) {
			autoModelFieldLocks = { ...autoModelFieldLocks, [key]: false };
		}
	};

	const safeParseModelTypeOverrides = (raw: string): ModelTypeRow[] => {
		try {
			const parsed = JSON.parse(raw || '{}');
			if (!parsed || typeof parsed !== 'object') return [];
			return Object.entries(parsed)
				.map(([modelId, taskType]) => {
					const model_id = String(modelId || '').trim();
					const task_type = String(taskType || '').trim().toUpperCase() as ModelTaskType;
					if (!model_id || !TASK_TYPES.includes(task_type)) return null;
					return { model_id, task_type };
				})
				.filter(Boolean) as ModelTypeRow[];
		} catch {
			return [];
		}
	};

	const normalizeModelTypeRows = (rows: ModelTypeRow[]): ModelTypeRow[] => {
		const seen = new Set<string>();
		const fallbackModelId = availableModels[0]?.id ?? '';
		return rows
			.map((row) => {
				const model_id = String(row?.model_id ?? '').trim();
				const task_type = TASK_TYPES.includes(row?.task_type as ModelTaskType)
					? (row.task_type as ModelTaskType)
					: 'GENERAL';
				const resolvedModelId = model_id || fallbackModelId;
				if (!resolvedModelId) return null;
				if (seen.has(resolvedModelId)) return null;
				seen.add(resolvedModelId);
				return { model_id: resolvedModelId, task_type };
			})
			.filter(Boolean) as ModelTypeRow[];
	};

	const syncOverridesJsonFromRows = () => {
		modelTypeRows = normalizeModelTypeRows(modelTypeRows);
		const entries = modelTypeRows
			.map((row) => [String(row.model_id || '').trim(), row.task_type] as const)
			.filter(([modelId, taskType]) => modelId && TASK_TYPES.includes(taskType));
		const payload = Object.fromEntries(entries);
		featureSettings = { ...featureSettings, auto_model_type_overrides_json: JSON.stringify(payload) };
	};

	const addModelTypeRow = () => {
		const firstModel = availableModels[0]?.id ?? '';
		if (!firstModel) {
			toast.error(tr('Список моделей пуст, добавить соответствие нельзя', 'Model list is empty, cannot add mapping'));
			return;
		}
		modelTypeRows = [...modelTypeRows, { model_id: firstModel, task_type: 'GENERAL' }];
		syncOverridesJsonFromRows();
	};

	const removeModelTypeRow = (index: number) => {
		modelTypeRows = modelTypeRows.filter((_, idx) => idx !== index);
		syncOverridesJsonFromRows();
	};

	const modelExistsInList = (modelId: string): boolean =>
		availableModels.some((model) => model.id === String(modelId || '').trim());

	const effectiveModelType = (model: SelectModelOption): ModelTaskType => {
		const override = modelTypeRows.find((row) => row.model_id === model.id)?.task_type;
		return override ?? model.inferred_type;
	};

	const classifierModelOptions = () =>
		availableModels.filter((model) => {
			const t = effectiveModelType(model);
			return t === 'GENERAL' || t === 'CODING' || t === 'REASONING';
		});

	const modelCourtJudgeModelOptions = () =>
		availableModels.filter((model) => effectiveModelType(model) !== 'IMAGE_GENERATION');

	const taskModelOptions = (taskType: ModelTaskType) =>
		availableModels.filter((model) => effectiveModelType(model) === taskType);

	const multimodalSttModelOptions = () =>
		availableModels.filter((model) => {
			const id = String(model.id || '').toLowerCase();
			const label = String(model.label || '').toLowerCase();
			return id.includes('whisper') || label.includes('whisper');
		});


	$: {
		const raw = String(featureSettings.auto_model_type_overrides_json || '{}');
		if (raw !== lastAppliedOverridesJson) {
			modelTypeRows = normalizeModelTypeRows(safeParseModelTypeOverrides(raw));
			lastAppliedOverridesJson = raw;
		}
	}

	$: {
		if (!defaultAvatarFile && featureSettings.default_model_avatar_url) {
			defaultAvatarPreviewUrl = `${WEBUI_API_BASE_URL}/gpthub/feature-settings/default-avatar?v=${Date.now()}`;
		}
	}

	$: {
		if (featureSettingsReady && !featureLoading) {
			const whisperOptions = multimodalSttModelOptions();
			if (!featureSettings.multimodal_stt_model && whisperOptions.length > 0) {
				featureSettings = { ...featureSettings, multimodal_stt_model: whisperOptions[0].id };
			}
		}
	}


	$: {
		if (!featureSettingsReady || featureLoading) {
			// no-op until initial settings are loaded
		} else {
			const snapshot = JSON.stringify(buildFeaturePayload(featureSettings));
			if (snapshot !== lastSavedFeatureSettingsSnapshot) {
				if (autosaveTimer) clearTimeout(autosaveTimer);
				autosaveTimer = setTimeout(() => {
					persistFeatureSettings();
				}, 450);
			}
		}
	}

	const runClassifierBenchmarkHandler = async () => {
		classifierBenchmarkLoading = true;
		classifierBenchmarkProgress = 5;
		if (classifierProgressTimer) clearInterval(classifierProgressTimer);
		classifierProgressTimer = setInterval(() => {
			classifierBenchmarkProgress = Math.min(95, classifierBenchmarkProgress + 1);
		}, 500);
		try {
			classifierBenchmarkResult = await runClassifierBenchmark(localStorage.token);
			toast.success(tr('Бенчмарк классификатора завершен', 'Classifier benchmark completed'));
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось запустить бенчмарк классификатора', 'Failed to run classifier benchmark'));
		} finally {
			if (classifierProgressTimer) {
				clearInterval(classifierProgressTimer);
				classifierProgressTimer = null;
			}
			classifierBenchmarkProgress = 100;
			setTimeout(() => {
				classifierBenchmarkProgress = 0;
			}, 600);
			classifierBenchmarkLoading = false;
		}
	};

	const applyClassifierWinnerHandler = async () => {
		const winnerModelId = classifierBenchmarkResult?.winner_model_id;
		if (!winnerModelId) {
			toast.error(tr('Победитель не определен', 'Winner is not defined'));
			return;
		}
		classifierBenchmarkApplying = true;
		try {
			const updated = await applyClassifierBenchmarkWinner(localStorage.token, winnerModelId);
			featureSettings = { ...defaultFeatureSettings, ...(updated ?? {}) };
			lastSavedFeatureSettingsSnapshot = JSON.stringify(buildFeaturePayload(featureSettings));
			toast.success(tr('Победитель установлен как модель-классификатор', 'Winner applied as classifier model'));
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось применить победителя', 'Failed to apply winner'));
		} finally {
			classifierBenchmarkApplying = false;
		}
	};

	const runTextBenchmarkHandler = async () => {
		textBenchmarkLoading = true;
		textBenchmarkProgress = 5;
		if (textProgressTimer) clearInterval(textProgressTimer);
		textProgressTimer = setInterval(() => {
			textBenchmarkProgress = Math.min(95, textBenchmarkProgress + 1);
		}, 500);
		try {
			textBenchmarkResult = await runTextBenchmark(localStorage.token);
			toast.success(tr('Текстовый бенчмарк завершен', 'Text benchmark completed'));
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось запустить текстовый бенчмарк', 'Failed to run text benchmark'));
		} finally {
			if (textProgressTimer) {
				clearInterval(textProgressTimer);
				textProgressTimer = null;
			}
			textBenchmarkProgress = 100;
			setTimeout(() => {
				textBenchmarkProgress = 0;
			}, 600);
			textBenchmarkLoading = false;
		}
	};

	const textBenchmarkWinners = () => {
		const entries = textBenchmarkResult?.entries ?? [];
		const pick = (category: string) =>
			entries
				.filter((e) => e.category === category)
				.sort((a, b) => (b.score - a.score) || (b.answered - a.answered))[0]?.model_id ?? '';
		const winners = {
			GENERAL: pick('GENERAL'),
			CODING: pick('CODING'),
			REASONING: pick('REASONING')
		};
		return winners;
	};

	const applyTextBenchmarkWinnersHandler = async () => {
		const winners = textBenchmarkWinners();
		if (!winners.GENERAL || !winners.CODING || !winners.REASONING) {
			toast.error(tr('Победители по категориям еще не определены', 'Winners by category are not defined yet'));
			return;
		}
		textBenchmarkApplying = true;
		try {
			const updated = await updateFeatureSettings(localStorage.token, {
				auto_task_model_general: winners.GENERAL,
				auto_task_model_coding: winners.CODING,
				auto_task_model_reasoning: winners.REASONING
			});
			featureSettings = { ...defaultFeatureSettings, ...(updated ?? {}) };
			lastSavedFeatureSettingsSnapshot = JSON.stringify(buildFeaturePayload(featureSettings));
			toast.success(tr('Победители применены в маппинг задач', 'Winners applied to task mapping'));
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось применить победителей', 'Failed to apply winners'));
		} finally {
			textBenchmarkApplying = false;
		}
	};

	const onDefaultAvatarFileChange = (event: Event) => {
		const input = event.currentTarget as HTMLInputElement;
		const file = input.files?.[0] ?? null;
		defaultAvatarFile = file;
		defaultAvatarFilename = file?.name ?? '';
		if (!file) return;
		const allowed = ['image/jpeg', 'image/png', 'image/svg+xml'];
		const ext = file.name.toLowerCase().split('.').pop() ?? '';
		const extAllowed = ['jpg', 'jpeg', 'png', 'svg'].includes(ext);
		if (!extAllowed || (file.type && !allowed.includes(file.type))) {
			toast.error(tr('Допустимые форматы: jpg, jpeg, png, svg', 'Allowed formats: jpg, jpeg, png, svg'));
			defaultAvatarFile = null;
			defaultAvatarFilename = '';
			input.value = '';
			return;
		}
		defaultAvatarPreviewUrl = URL.createObjectURL(file);
	};

	const saveDefaultAvatar = async () => {
		if (!defaultAvatarFile) {
			toast.error(tr('Сначала выберите файл аватарки', 'Select avatar file first'));
			return;
		}
		defaultAvatarUploading = true;
		try {
			const result = await uploadDefaultModelAvatar(localStorage.token, defaultAvatarFile);
			if (result?.default_model_avatar_url) {
				featureSettings = {
					...featureSettings,
					default_model_avatar_url: String(result.default_model_avatar_url)
				};
			}
			defaultAvatarFile = null;
			defaultAvatarFilename = '';
			defaultAvatarPreviewUrl = `${WEBUI_API_BASE_URL}/gpthub/feature-settings/default-avatar?v=${Date.now()}`;
			toast.success(tr('Аватарка модели сохранена', 'Model avatar saved'));
		} catch (error) {
			console.error(error);
			toast.error(tr('Не удалось сохранить аватарку', 'Failed to save avatar'));
		} finally {
			defaultAvatarUploading = false;
		}
	};

	onMount(async () => {
		await Promise.all([refreshGeneral(), refreshFeatureSettings(), refreshAvailableModels()]);
		defaultAvatarPreviewUrl = `${WEBUI_API_BASE_URL}/gpthub/feature-settings/default-avatar?v=${Date.now()}`;
		await loadBenchmarkHistory();
	});
</script>

