						<Tooltip content={tip('Включает демо-ответы вместо реальных вызовов. Нужен для быстрых проверок сценариев без затрат токенов.')}>
							<span class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 dark:border-gray-700 dark:text-gray-400 cursor-help">?</span>
						</Tooltip>
