					<div class="mt-3 flex items-center justify-between rounded-lg border border-gray-200 dark:border-gray-800 px-3 py-2">
						<span class="text-xs font-medium">{tr('Включить stub-режим', 'Enable stub mode')}</span>
						<Switch state={featureSettings.mws_stub_mode} on:change={(e) => (featureSettings = { ...featureSettings, mws_stub_mode: e.detail })} />
