						<Tooltip content={tip('Базовая аватарка для моделей без своей иконки.', 'Fallback avatar used when a model has no own icon.')}>
							<span class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 cursor-help">?</span>
