					<div class="border border-gray-200 dark:border-gray-800 rounded-lg px-3 py-2 flex items-center justify-between"><div class="text-xs font-medium flex items-center gap-2">Workspace Templates<Tooltip content={tip('Шаблоны структуры workspace для быстрого старта.') }><span class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 cursor-help">?</span></Tooltip></div><Switch state={featureSettings.workspace_enable_workspace_templates} on:change={(e) => (featureSettings = { ...featureSettings, workspace_enable_workspace_templates: e.detail })} /></div>
					<div class="border border-gray-200 dark:border-gray-800 rounded-lg px-3 py-2"><div class="text-xs font-medium flex items-center gap-2">Max Files Per Workspace<Tooltip content={tip('Лимит файлов в одном workspace для защиты производительности.') }><span class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 cursor-help">?</span></Tooltip></div><input type="number" min="100" max="10000" class="mt-2 w-full bg-transparent border border-gray-200 dark:border-gray-800 rounded-lg px-3 py-2 outline-hidden focus:ring-0 focus:outline-none" value={String(featureSettings.workspace_max_files_per_workspace)} on:input={(e) => updateFeatureNumber('workspace_max_files_per_workspace', (e.currentTarget as HTMLInputElement).value)} /></div>
				</div>
				</div>
			</div>
			{/if}
		</div>
	</div>
</div>
