<script lang="ts">
	import { getContext, onMount } from 'svelte';
	import { toast } from 'svelte-sonner';

	import { getAdminConfig, updateAdminConfig } from '$lib/apis/auths';
	import Switch from '$lib/components/common/Switch.svelte';
	import Tooltip from '$lib/components/common/Tooltip.svelte';

	const i18n = getContext('i18n');
	export let saveHandler: Function;

	let adminConfig = null;

	const tip = (text: string) => {
		return `<div style="max-width: 320px; white-space: normal; text-align: left;">${text}</div>`;
	};

	const updateHandler = async () => {
		const res = await updateAdminConfig(localStorage.token, adminConfig);
		if (res) {
			saveHandler();
		} else {
			toast.error($i18n.t('Failed to update settings'));
		}
	};

	onMount(async () => {
		adminConfig = await getAdminConfig(localStorage.token);
	});
</script>

<form
	class="flex flex-col h-full justify-between space-y-3 text-sm"
	on:submit|preventDefault={async () => {
		updateHandler();
	}}
>
	<div class="space-y-3 overflow-y-scroll scrollbar-hidden h-full">
		{#if adminConfig !== null}
			<div class="mb-3">
				<div class="mt-0.5 mb-2.5 text-base font-medium">{$i18n.t('Interactions')}</div>
				<div class="text-xs text-gray-500 mb-3">
					{$i18n.t('Settings that control collaboration and user-to-user behavior in the interface.')}
				</div>
				<hr class="border-gray-100/30 dark:border-gray-850/30 my-2" />

				<div class="mb-2.5 flex w-full items-center justify-between pr-2">
					<div class="self-center text-xs font-medium flex items-center gap-2">
						{$i18n.t('Enable Community Sharing')}
						<Tooltip content={tip($i18n.t('TIP_ENABLE_COMMUNITY_SHARING'))}>
							<span
								class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 dark:border-gray-700 dark:text-gray-400 cursor-help"
								>?</span
							>
						</Tooltip>
					</div>
					<Switch bind:state={adminConfig.ENABLE_COMMUNITY_SHARING} />
				</div>

				<div class="mb-2.5 flex w-full items-center justify-between pr-2">
					<div class="self-center text-xs font-medium flex items-center gap-2">
						{$i18n.t('Channels')} ({$i18n.t('Beta')})
						<Tooltip content={tip($i18n.t('TIP_CHANNELS_BETA'))}>
							<span
								class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 dark:border-gray-700 dark:text-gray-400 cursor-help"
								>?</span
							>
						</Tooltip>
					</div>
					<Switch bind:state={adminConfig.ENABLE_CHANNELS} />
				</div>

				<div class="mb-2.5 flex w-full items-center justify-between pr-2">
					<div class="self-center text-xs font-medium flex items-center gap-2">
						{$i18n.t('User Status')}
						<Tooltip content={tip($i18n.t('TIP_USER_STATUS'))}>
							<span
								class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 dark:border-gray-700 dark:text-gray-400 cursor-help"
								>?</span
							>
						</Tooltip>
					</div>
					<Switch bind:state={adminConfig.ENABLE_USER_STATUS} />
				</div>

				<div class="mb-2.5 flex w-full items-center justify-between pr-2">
					<div class="self-center text-xs font-medium flex items-center gap-2">
						{$i18n.t('Enable Message Rating')}
						<Tooltip content={tip($i18n.t('TIP_ENABLE_MESSAGE_RATING'))}>
							<span
								class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 dark:border-gray-700 dark:text-gray-400 cursor-help"
								>?</span
							>
						</Tooltip>
					</div>
					<Switch bind:state={adminConfig.ENABLE_MESSAGE_RATING} />
				</div>

				<div class="mb-2.5 flex w-full items-center justify-between pr-2">
					<div class="self-center text-xs font-medium flex items-center gap-2">
						{$i18n.t('User Webhooks')}
						<Tooltip content={tip($i18n.t('TIP_USER_WEBHOOKS'))}>
							<span
								class="inline-flex h-4 w-4 items-center justify-center rounded-full border border-gray-300 text-[10px] text-gray-500 dark:border-gray-700 dark:text-gray-400 cursor-help"
								>?</span
							>
						</Tooltip>
					</div>
					<Switch bind:state={adminConfig.ENABLE_USER_WEBHOOKS} />
				</div>
			</div>
		{/if}
	</div>

	<div class="flex justify-end pt-3 text-sm font-medium">
		<button
			class="px-3.5 py-1.5 text-sm font-medium bg-black hover:bg-gray-900 text-white dark:bg-white dark:text-black dark:hover:bg-gray-100 transition rounded-full"
			type="submit"
		>
			{$i18n.t('Save')}
		</button>
	</div>
</form>
